@page "/chat"
@using sv_b6e4392772b14002b520aefe1c54aeee.Services
@inject IChatService ChatService
@rendermode InteractiveServer

<PageTitle>Chat</PageTitle>

<div class="chat-layout">
    <ChannelSidebar Channels="channels"
                    ActiveChannelId="activeChannelId"
                    OnChannelSelected="SelectChannel" />

    <div class="main-area @(threadRootMessage is not null ? "thread-open" : "")">
        @if (activeChannel is not null)
        {
            <div class="area-header">
                <h2># @activeChannel.Name</h2>
                <p>@activeChannel.Description</p>
            </div>

            <div class="message-list" @onscroll="HandleScroll" @ref="messageListRef">
                @if (isLoadingMore)
                {
                    <div class="loading-indicator">Loading older messages…</div>
                }
                @foreach (var msg in messages)
                {
                    <MessageItem Message="msg"
                                 ThreadReplyCount="GetThreadReplyCount(msg.Id)"
                                 OnOpenThread="OpenThread"
                                 OnReact="HandleReaction" />
                }
            </div>

            <MessageInput Placeholder="Message #@activeChannel.Name"
                          OnSend="SendMessage" />
        }
        else
        {
            <div class="no-channel-selected">
                <p>Select a channel to start chatting</p>
            </div>
        }
    </div>

    @if (threadRootMessage is not null)
    {
        <ThreadPanel RootMessage="threadRootMessage"
                     Replies="threadReplies"
                     OnClose="CloseThread"
                     OnSendReply="SendThreadReply" />
    }
</div>

@code {
    private List<Channel> channels = [];
    private List<Message> messages = [];
    private List<Message> threadReplies = [];
    private Dictionary<int, int> threadReplyCounts = new();
    private Channel? activeChannel;
    private int activeChannelId;
    private Message? threadRootMessage;
    private bool isLoadingMore;
    private bool hasMoreMessages = true;
    private const int PageSize = 30;
    private ElementReference messageListRef;

    protected override async Task OnInitializedAsync()
    {
        channels = await ChatService.GetChannelsAsync();
        if (channels.Count > 0)
        {
            await SelectChannel(channels[0].Id);
        }
    }

    private async Task SelectChannel(int channelId)
    {
        activeChannelId = channelId;
        activeChannel = channels.FirstOrDefault(c => c.Id == channelId);
        messages = [];
        threadReplyCounts.Clear();
        hasMoreMessages = true;

        var loaded = await ChatService.GetMessagesAsync(channelId, 0, PageSize);
        messages = loaded;
        hasMoreMessages = loaded.Count == PageSize;

        await BuildThreadCounts();
        await ChatService.MarkChannelReadAsync(channelId);
        UpdateChannelUnread(channelId);
    }

    private async Task HandleScroll()
    {
        // Scroll-to-top triggers loading older messages
        if (isLoadingMore || !hasMoreMessages) return;

        isLoadingMore = true;
        StateHasChanged();

        var older = await ChatService.GetMessagesAsync(activeChannelId, messages.Count, PageSize);
        hasMoreMessages = older.Count == PageSize;
        messages.InsertRange(0, older);
        await BuildThreadCounts();

        isLoadingMore = false;
    }

    private async Task SendMessage(string content)
    {
        var msg = await ChatService.SendMessageAsync(activeChannelId, content, null);
        messages.Add(msg);
    }

    private async Task OpenThread(int rootMessageId)
    {
        threadRootMessage = messages.FirstOrDefault(m => m.Id == rootMessageId);
        if (threadRootMessage is null) return;

        threadReplies = await ChatService.GetThreadAsync(rootMessageId);
    }

    private void CloseThread()
    {
        threadRootMessage = null;
        threadReplies = [];
    }

    private async Task SendThreadReply(string content)
    {
        if (threadRootMessage is null) return;

        var reply = await ChatService.SendMessageAsync(
            activeChannelId, content, threadRootMessage.Id);
        threadReplies.Add(reply);

        // Update thread reply count
        threadReplyCounts[threadRootMessage.Id] =
            threadReplyCounts.GetValueOrDefault(threadRootMessage.Id) + 1;
    }

    private async Task HandleReaction((int MessageId, string Emoji) args)
    {
        await ChatService.AddReactionAsync(args.MessageId, args.Emoji);

        // Optimistically update the reaction in the local message list
        var msg = messages.FirstOrDefault(m => m.Id == args.MessageId);
        if (msg is not null)
        {
            var existing = msg.Reactions.FirstOrDefault(r => r.Emoji == args.Emoji);
            if (existing is not null)
            {
                existing.Users.Add("You");
            }
            else
            {
                msg.Reactions.Add(new Reaction(args.Emoji, ["You"]));
            }
        }
    }

    private int GetThreadReplyCount(int messageId) =>
        threadReplyCounts.GetValueOrDefault(messageId);

    private async Task BuildThreadCounts()
    {
        // Identify root messages (those not replying to another) that might have threads
        foreach (var msg in messages.Where(m => m.ReplyToId is null))
        {
            if (!threadReplyCounts.ContainsKey(msg.Id))
            {
                var replies = await ChatService.GetThreadAsync(msg.Id);
                if (replies.Count > 0)
                {
                    threadReplyCounts[msg.Id] = replies.Count;
                }
            }
        }
    }

    private void UpdateChannelUnread(int channelId)
    {
        var idx = channels.FindIndex(c => c.Id == channelId);
        if (idx >= 0)
        {
            channels[idx] = channels[idx] with { UnreadCount = 0 };
        }
    }
}

