toolArgs.file_text:
.chat-layout {
    display: flex;
    height: 100vh;
    overflow: hidden;
    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif;
}

/* --- Channel Sidebar --- */

::deep .channel-sidebar {
    width: 20%;
    min-width: 200px;
    background: #2c2f33;
    color: #dcddde;
    display: flex;
    flex-direction: column;
    border-right: 1px solid #202225;
}

::deep .sidebar-header {
    padding: 16px;
    border-bottom: 1px solid #202225;
}

::deep .sidebar-header h3 {
    margin: 0;
    font-size: 1rem;
    text-transform: uppercase;
    letter-spacing: 0.05em;
    color: #8e9297;
}

::deep .channel-list {
    flex: 1;
    overflow-y: auto;
    padding: 8px 0;
}

::deep .channel-item {
    display: block;
    width: 100%;
    padding: 8px 16px;
    border: none;
    background: none;
    color: #8e9297;
    text-align: left;
    cursor: pointer;
    transition: background-color 0.15s;
}

::deep .channel-item:hover {
    background: #36393f;
    color: #dcddde;
}

::deep .channel-item.active {
    background: #393c43;
    color: #fff;
}

::deep .channel-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
}

::deep .channel-name {
    font-weight: 600;
    font-size: 0.95rem;
}

::deep .unread-badge {
    background: #ed4245;
    color: #fff;
    font-size: 0.7rem;
    font-weight: 700;
    padding: 2px 6px;
    border-radius: 10px;
    min-width: 18px;
    text-align: center;
}

::deep .channel-description {
    font-size: 0.75rem;
    color: #72767d;
    margin-top: 2px;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

/* --- Main Message Area --- */

.main-area {
    flex: 1;
    display: flex;
    flex-direction: column;
    background: #36393f;
    color: #dcddde;
    min-width: 0;
}

.main-area.thread-open {
    max-width: 55%;
}

.area-header {
    padding: 12px 20px;
    border-bottom: 1px solid #202225;
    background: #36393f;
}

.area-header h2 {
    margin: 0;
    font-size: 1.1rem;
    color: #fff;
}

.area-header p {
    margin: 4px 0 0;
    font-size: 0.8rem;
    color: #8e9297;
}

.message-list {
    flex: 1;
    overflow-y: auto;
    padding: 16px 20px;
}

.no-channel-selected {
    flex: 1;
    display: flex;
    align-items: center;
    justify-content: center;
    color: #72767d;
    font-size: 1.1rem;
}

.loading-indicator {
    text-align: center;
    padding: 12px;
    color: #8e9297;
    font-size: 0.85rem;
}

/* --- Message Item --- */

::deep .message-item {
    position: relative;
    padding: 8px 12px;
    border-radius: 4px;
    margin-bottom: 4px;
    transition: background-color 0.1s;
}

::deep .message-item:hover {
    background: #32353b;
}

::deep .message-header {
    display: flex;
    align-items: baseline;
    gap: 8px;
    margin-bottom: 2px;
}

::deep .message-author {
    font-weight: 600;
    color: #fff;
    font-size: 0.95rem;
}

::deep .message-time {
    font-size: 0.7rem;
    color: #72767d;
}

::deep .message-content {
    font-size: 0.9rem;
    line-height: 1.4;
    color: #dcddde;
    word-wrap: break-word;
}

/* --- Reactions --- */

::deep .reaction-bar {
    display: flex;
    gap: 4px;
    margin-top: 6px;
    flex-wrap: wrap;
}

::deep .reaction-badge {
    display: inline-flex;
    align-items: center;
    gap: 4px;
    padding: 2px 8px;
    background: #2f3136;
    border: 1px solid #40444b;
    border-radius: 12px;
    cursor: pointer;
    font-size: 0.8rem;
    color: #dcddde;
    transition: background-color 0.15s;
}

::deep .reaction-badge:hover {
    background: #40444b;
}

::deep .reaction-count {
    font-size: 0.75rem;
    font-weight: 600;
}

/* --- Thread Link --- */

::deep .thread-link {
    display: inline-block;
    margin-top: 6px;
    background: none;
    border: none;
    color: #00aff4;
    font-size: 0.8rem;
    cursor: pointer;
    padding: 0;
}

::deep .thread-link:hover {
    text-decoration: underline;
}

/* --- Hover Actions --- */

::deep .message-actions {
    position: absolute;
    top: -8px;
    right: 8px;
    display: flex;
    gap: 4px;
